// Parse la réponse Mistral chat completion en JSON profil+planning
const resp = $input.first().json;
const built = $('Build Agent Input').first().json || {};

let content = '';
try {
  content = resp.choices && resp.choices[0] && resp.choices[0].message ? resp.choices[0].message.content : '';
} catch(e) { content = ''; }

if (!content) {
  throw new Error('Réponse Mistral vide ou invalide : ' + JSON.stringify(resp).slice(0, 500));
}

let cleaned = String(content).trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/, '')
  .replace(/```\s*$/, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (m) {
    try { parsed = JSON.parse(m[0]); }
    catch(e2) {
      throw new Error('Impossible de parser le JSON Mistral : ' + e2.message + ' | content: ' + cleaned.slice(0, 500));
    }
  } else {
    throw new Error('Aucun JSON détecté dans la réponse Mistral. Content: ' + cleaned.slice(0, 500));
  }
}

return [{
  json: {
    eleve: built.eleve,
    profil: parsed.profil,
    planning: parsed.planning,
    scoresdeterministes: built.scores,
    bulletinstructure: built.bulletin_structure || null,
    generatedat: new Date().toISOString()
  }
}];

const input = $input.first().json;

// Supporte les 2 cas : payload direct ou payload dans body (Webhook)
const payload = input.body && typeof input.body === 'object' ? input.body : input;

const eleve = payload.eleve || {};
const reponses = Array.isArray(payload.reponses) ? payload.reponses : [];
const emploi_du_temps_src = payload.emploi_du_temps || {};
const dates_examens_src = Array.isArray(payload.dates_examens) ? payload.dates_examens : [];

const groupsMap = {
  Perfectionniste: ['Q01','Q02','Q03','Q04'],
  Aimable: ['Q05','Q06','Q07','Q08'],
  Dynamique: ['Q09','Q10','Q11','Q12'],
  Rebelle: ['Q13','Q14','Q15','Q16'],
  Intellectuel: ['Q17','Q18','Q19','Q20'],
  Enthousiaste: ['Q21','Q22','Q23','Q24'],
  'Émotionnel': ['Q25','Q26','Q27','Q28'],
  Visuel: ['Q29','Q30','Q31','Q32'],
  Auditif: ['Q33','Q34','Q35','Q36'],
  Kinesthesique: ['Q37','Q38','Q39','Q40'],
};

const repMap = {};
for (const r of reponses) {
  if (!r || !r.question_id) continue;
  repMap[r.question_id] = String(r.reponse || '').toUpperCase().trim();
}

function isOui(qid) {
  const v = repMap[qid] || 'NON';
  return ['OUI', 'YES', 'TRUE', '1'].includes(v);
}

function scoreGroup(qids) {
  return qids.reduce((acc, qid) => acc + (isOui(qid) ? 1 : 0), 0);
}

// Identité
const identite_raw = {
  Perfectionniste: scoreGroup(groupsMap.Perfectionniste),
  Aimable: scoreGroup(groupsMap.Aimable),
  Dynamique: scoreGroup(groupsMap.Dynamique),
  Rebelle: scoreGroup(groupsMap.Rebelle),
  Intellectuel: scoreGroup(groupsMap.Intellectuel),
  Enthousiaste: scoreGroup(groupsMap.Enthousiaste),
  'Émotionnel': scoreGroup(groupsMap['Émotionnel']),
};

const total_identite = Object.values(identite_raw).reduce((a, b) => a + b, 0);
const identite_pct = {};
for (const [k, v] of Object.entries(identite_raw)) {
  identite_pct[k] = total_identite > 0 ? Math.round((v / total_identite) * 1000) / 10 : 0;
}

const sortedIdent = Object.entries(identite_raw).sort((a, b) => b[1] - a[1]);
const identite_dominante = sortedIdent[0]?.[0] || 'Perfectionniste';
const identite_secondaire = sortedIdent[1]?.[0] || 'Aimable';

// VAK
const vak_raw = {
  Visuel: scoreGroup(groupsMap.Visuel),
  Auditif: scoreGroup(groupsMap.Auditif),
  Kinesthesique: scoreGroup(groupsMap.Kinesthesique),
};

const total_vak = Object.values(vak_raw).reduce((a, b) => a + b, 0);
let vak_pct;

if (total_vak === 0) {
  vak_pct = {
    Visuel: 58,
    Auditif: 27,
    Kinesthesique: 15,
    _note: 'Moyenne nationale par défaut'
  };
} else {
  vak_pct = {
    Visuel: Math.round((vak_raw.Visuel / total_vak) * 1000) / 10,
    Auditif: Math.round((vak_raw.Auditif / total_vak) * 1000) / 10,
    Kinesthesique: Math.round((vak_raw.Kinesthesique / total_vak) * 1000) / 10,
  };
}

const canal_dominant = Object.entries(vak_pct)
  .filter(([k]) => !k.startsWith('_'))
  .sort((a, b) => b[1] - a[1])[0]?.[0] || 'Visuel';

// Emploi du temps
const emploi_du_temps = {
  ...emploi_du_temps_src,
  Q47: payload.volume_chapitres_jour || emploi_du_temps_src.Q47 || null,
  Q48: payload.duree_transport || emploi_du_temps_src.Q48 || null,
};

// Dates
const dates_examens = dates_examens_src;
const dates_examens_raw = Array.isArray(dates_examens_src)
  ? dates_examens_src.join(', ')
  : String(dates_examens_src || '');

// Bulletin
const bin = $binary || {};
const binKeys = Object.keys(bin);
const bulletinBinKey =
  binKeys.find(k => k.toLowerCase().includes('bulletin')) ||
  (binKeys.length > 0 ? binKeys[0] : null);

const hasBulletinBinary = !!bulletinBinKey;
const bulletinBase64 = payload.bulletin_base64 || null;
const hasBulletin = hasBulletinBinary || !!bulletinBase64;

return [{
  json: {
    eleve: {
      prenom: eleve.prenom || '',
      nom: eleve.nom || '',
      email: eleve.email || '',
      date_naissance: eleve.date_naissance || null
    },
    scores: {
      identite: {
        raw: identite_raw,
        pct: identite_pct,
        dominante: identite_dominante,
        secondaire: identite_secondaire
      },
      vak: {
        raw: vak_raw,
        pct: vak_pct,
        dominant: canal_dominant
      }
    },
    emploi_du_temps,
    dates_examens,
    dates_examens_raw,
    has_bulletin: hasBulletin,
    bulletin_bin_key: bulletinBinKey,
    bulletin_base64: bulletinBase64,
    moyennes_nationales: {
      identite: {
        Perfectionniste: 22,
        Aimable: 18,
        'Émotionnel': 16,
        Intellectuel: 14,
        Enthousiaste: 13,
        Dynamique: 10,
        Rebelle: 7
      },
      vak: {
        Visuel: 58,
        Auditif: 27,
        Kinesthesique: 15
      }
    }
  },
  binary: bin
}];

// Construit la ligne questionnaires (FK eleve_id)
  var answers = {};
  try { answers = $('On form submission1').first().json; } catch(e) {
    try { var w = $('Webhook').first().json; answers = (w && w.body) ? w.body : (w||{}); } catch(e2) { answers = {}; }
  }
var cs = $('Calcul scores (JS)').first().json;
var sc = cs.scores || {};
var ident = sc.identite || {};
var vak = sc.vak || {};
var edt = cs.emploi_du_temps || {};
return [{ json: {
  eleve_id: $('Insert eleve').first().json.id,
  identite_dominante: ident.dominante || null,
  identite_secondaire: ident.secondaire || null,
  scores_identite_pct: ident.pct || {},
  canaux_vak_pct: vak.pct || {},
  canal_dominant: vak.dominant || null,
  emploi_du_temps: edt,
  dates_examens: cs.dates_examens || [],
  volume_chapitres_jour: edt.Q47 || null,
  duree_transport: edt.Q48 || null,
  has_bulletin: cs.has_bulletin === true,
  source_mode: answers.formMode || null,
  submitted_at: answers.submittedAt || null
} }];

// Eclate les 40 reponses Q01..Q40 en lignes reponses_questionnaire
  var answers = {};
  try { answers = $('On form submission1').first().json; } catch(e) {
    try { var w = $('Webhook').first().json; answers = (w && w.body) ? w.body : (w||{}); } catch(e2) { answers = {}; }
  }
var qid = $('Insert questionnaire').first().json.id;
var rows = [];
for (var key in answers) {
  if (!Object.prototype.hasOwnProperty.call(answers, key)) continue;
  var head = key.match(/^Q(\d{1,2})\b/);
  if (!head) continue;
  var num = parseInt(head[1], 10);
  if (num < 1 || num > 40) continue;
  var full = key.match(/^(Q\d+)\s*\(([^)]*)\)\s*[\u2014-]\s*(.+)$/);
  var qId, groupe, libelle;
  if (full) { qId = full[1]; groupe = full[2]; libelle = full[3]; }
  else { qId = 'Q' + ('0'+num).slice(-2); groupe = null; libelle = key; }
  rows.push({ json: {
    questionnaire_id: qid,
    question_id: qId,
    groupe: groupe,
    libelle: libelle,
    reponse: String(answers[key])
  } });
}
return rows;

// Construit la ligne profils (FK questionnaire_id)
var p = ($('Parse Agent Output').first().json.profil) || {};
return [{ json: {
  questionnaire_id: $('Insert questionnaire').first().json.id,
  motivation: p.motivation || null,
  synthese_narrative: p.synthesenarrative || null,
  conseil_strategique: p.conseilstrategique || null,
  preuves_bulletin: p.preuvesbulletin || []
} }];

// Construit la ligne plannings (FK questionnaire_id)
var pl = ($('Parse Agent Output').first().json.planning) || {};
return [{ json: {
  questionnaire_id: $('Insert questionnaire').first().json.id,
  examens_cibles: pl.examenscibles || [],
  notes_methodo: pl.notesmethodo || null
} }];

// Eclate semainetype -> lignes planning_creneaux (FK planning_id)
var pl = ($('Parse Agent Output').first().json.planning) || {};
var planningId = $('Insert planning').first().json.id;
var valid = ['cours','revision','sport','loisirs','sommeil','repas','transport','physio'];
var rows = [];
var sem = pl.semainetype || [];
for (var i=0;i<sem.length;i++){
  var day = sem[i]; var cr = day.creneaux || [];
  for (var j=0;j<cr.length;j++){
    var c = cr[j]; var t = String(c.type||'').toLowerCase().trim();
    if (valid.indexOf(t) === -1){
      if (t.indexOf('rev')>=0) t='revision';
      else if (t.indexOf('cour')>=0) t='cours';
      else if (t.indexOf('somm')>=0||t.indexOf('dort')>=0||t.indexOf('sleep')>=0) t='sommeil';
      else if (t.indexOf('repas')>=0||t.indexOf('manger')>=0) t='repas';
      else if (t.indexOf('transp')>=0) t='transport';
      else if (t.indexOf('sport')>=0) t='sport';
      else if (t.indexOf('lois')>=0) t='loisirs';
      else t='physio';
    }
    rows.push({ json: {
      planning_id: planningId,
      jour: day.jour,
      horaire: c.horaire,
      activite: c.activite,
      type: t,
      couleur: c.couleur || null
    } });
  }
}
return rows;

// Eclate sessionsJ -> lignes sessions_j (FK planning_id)
var pl = ($('Parse Agent Output').first().json.planning) || {};
var planningId = $('Insert planning').first().json.id;
var today;
try { today = $('Build Agent Input').first().json.today; } catch(e) { today = null; }
if (!today) today = new Date().toISOString().slice(0,10);
var validJ = ['J0','J1','J7','J14','J30','J60'];
var rows = [];
var arr = pl.sessionsJ || [];
for (var i=0;i<arr.length;i++){
  var s = arr[i];
  var tj = String(s.type||'').toUpperCase().trim();
  if (validJ.indexOf(tj) === -1) tj = 'J0';
  var d = parseInt(s.dureemin, 10);
  if (!isFinite(d) || d <= 0) d = null;
  rows.push({ json: {
    planning_id: planningId,
    date_session: s.date || today,
    type_j: tj,
    matiere: s.matiere || 'N/A',
    duree_min: d,
    couleur: s.couleur || null,
    techniques_vak: s.techniquesVAK || []
  } });
}
return rows;

// Construit la ligne bulletins (FK eleve_id + questionnaire_id)
  var answers = {};
  try { answers = $('On form submission1').first().json; } catch(e) {
    try { var w = $('Webhook').first().json; answers = (w && w.body) ? w.body : (w||{}); } catch(e2) { answers = {}; }
  }
var b = ($('Parse Agent Output').first().json.bulletinstructure) || {};
var filename = null;
for (var k in answers){
  if (k.toLowerCase().indexOf('bulletin') >= 0 && answers[k] && typeof answers[k] === 'object'){
    filename = answers[k].filename || null; break;
  }
}
return [{ json: {
  eleve_id: $('Insert eleve').first().json.id,
  questionnaire_id: $('Insert questionnaire').first().json.id,
  classe: b.classe || null,
  eleve_nom_bulletin: b.eleve_nom_bulletin || null,
  source_filename: filename
} }];

// Eclate trimestres -> lignes bulletin_trimestres (FK bulletin_id)
var b = ($('Parse Agent Output').first().json.bulletinstructure) || {};
var bid = $('Insert bulletin').first().json.id;
var arr = b.trimestres || [];
var rows = [];
for (var i=0;i<arr.length;i++){
  var t = arr[i];
  rows.push({ json: {
    bulletin_id: bid,
    periode: t.periode || null,
    moyenne_generale: (t.moyenne_generale === undefined ? null : t.moyenne_generale),
    appreciation_globale: t.appreciation_globale || null
  } });
}
return rows;

// Pour chaque trimestre insere, genere ses matieres (FK trimestre_id)
var b = ($('Parse Agent Output').first().json.bulletinstructure) || {};
var trimestres = b.trimestres || [];
var out = [];
var items = $input.all();
for (var i=0;i<items.length;i++){
  var row = items[i].json;
  var match = null;
  for (var j=0;j<trimestres.length;j++){
    if ((trimestres[j].periode||null) === (row.periode||null)) { match = trimestres[j]; break; }
  }
  var mats = (match && match.matieres) ? match.matieres : [];
  for (var k=0;k<mats.length;k++){
    var m = mats[k];
    out.push({ json: {
      trimestre_id: row.id,
      nom: m.nom || 'N/A',
      moyenne: (m.moyenne === undefined ? null : m.moyenne),
      commentaire: m.commentaire || null
    } });
  }
}
return out;

const uploadResp = $input.first().json;
const fileId = uploadResp.id || null;

let scoresData = {};
try { scoresData = $('Calcul scores (JS)1').first().json; } catch(e) {}

return [{
