const ocrResp = $input.first().json;
const pages = ocrResp.pages || [];
const ocrText = pages.map(p => p.markdown || p.text || '').join('\n\n').trim()
  || ocrResp.text || ocrResp.content || '';

let scoresData = {};
try { scoresData = $('Calcul scores (JS)1').first().json; } catch(e) {}

return [{
  json: {
    ...scoresData,
    ocr_text: ocrText,
