  }
}];

const raw = $input.first().json;
// Support both webhook-wrapped ({body: {...}}) and direct payloads
const formData = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

const subgroups = {
  A: ['Q01','Q02','Q03','Q04'],
  B: ['Q05','Q06','Q07','Q08'],
  C: ['Q09','Q10','Q11','Q12'],
  D: ['Q13','Q14','Q15','Q16'],
  E: ['Q17','Q18','Q19','Q20'],
  F: ['Q21','Q22','Q23','Q24'],
  G: ['Q25','Q26','Q27','Q28'],
  H: ['Q29','Q30','Q31','Q32'],
  I: ['Q33','Q34','Q35','Q36'],
  J: ['Q37','Q38','Q39','Q40'],
};

const labels = {
  A: 'Perfectionniste', B: 'Aimable', C: 'Dynamique', D: 'Rebelle',
  E: 'Intellectuel', F: 'Enthousiaste', G: 'Émotionnel',
  H: 'Visuel', I: 'Auditif', J: 'Kinesthesique'
};

function getAnswer(qid) {
  // 1. Direct key "Q01": "OUI" (format sent by the app)
  if (formData[qid] !== undefined) {
    const v = String(formData[qid]).toUpperCase().trim();
    return (v === 'OUI' || v === 'YES' || v === 'TRUE' || v === '1') ? 'OUI' : 'NON';
  }
  // 2. Legacy format "Q01 (label) — …": "OUI"
  const k = Object.keys(formData).find(key => key.startsWith(qid + ' ') || key.startsWith(qid + '('));
  if (k) {
    const v = String(formData[k]).toUpperCase().trim();
    return (v === 'OUI' || v === 'YES' || v === 'TRUE' || v === '1') ? 'OUI' : 'NON';
  }
  // 3. reponses array [{id:"Q01", valeur:"OUI"}, ...]
  if (Array.isArray(formData.reponses)) {
    const rep = formData.reponses.find(r => r.id === qid || r.question_id === qid);
    if (rep) {
      const v = String(rep.valeur ?? rep.value ?? rep.reponse ?? '').toUpperCase().trim();
      return (v === 'OUI' || v === 'YES' || v === 'TRUE' || v === '1') ? 'OUI' : 'NON';
    }
  }
  return 'NON';
}

function scoreGroup(qids) {
  return qids.reduce((acc, qid) => acc + (getAnswer(qid) === 'OUI' ? 1 : 0), 0);
}

const identite_raw = {};
for (const sg of ['A','B','C','D','E','F','G']) {
  identite_raw[labels[sg]] = scoreGroup(subgroups[sg]);
}
const total_identite = Object.values(identite_raw).reduce((a,b) => a+b, 0);
const identite_pct = {};
for (const [k,v] of Object.entries(identite_raw)) {
  identite_pct[k] = total_identite > 0 ? Math.round((v / total_identite) * 1000) / 10 : 0;
}
const sortedIdent = Object.entries(identite_raw).sort((a,b) => b[1]-a[1]);
const identite_dominante  = sortedIdent[0][0];
const identite_secondaire = sortedIdent[1][0];

const vak_raw = {
  Visuel:        scoreGroup(subgroups.H),
  Auditif:       scoreGroup(subgroups.I),
  Kinesthesique: scoreGroup(subgroups.J),
};
const total_vak = vak_raw.Visuel + vak_raw.Auditif + vak_raw.Kinesthesique;
let vak_pct;
if (total_vak === 0) {
  vak_pct = { Visuel: 58, Auditif: 27, Kinesthesique: 15, _note: 'Moyenne nationale par défaut' };
} else {
  vak_pct = {
    Visuel:        Math.round((vak_raw.Visuel        / total_vak) * 1000) / 10,
    Auditif:       Math.round((vak_raw.Auditif       / total_vak) * 1000) / 10,
    Kinesthesique: Math.round((vak_raw.Kinesthesique / total_vak) * 1000) / 10,
  };
}
const sortedVak = Object.entries(vak_raw).sort((a,b) => b[1]-a[1]);
const canal_dominant = sortedVak[0][0];

return [{
  json: {
    identite_dominante,
    identite_secondaire,
    identite_pct,
    vak_pct,
    canal_dominant,
  }
}];

