const resp = $input.first().json;
let content = '';
try { content = resp.choices[0].message.content || ''; } catch(e) { content = ''; }

let bulletinParsed = null;
if (content) {
  let cleaned = String(content).trim()
    .replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '').trim();
  try {
    bulletinParsed = JSON.parse(cleaned);
  } catch(e) {
    const m = cleaned.match(/\{[\s\S]*\}/);
    if (m) {
      try { bulletinParsed = JSON.parse(m); }
      catch(e2) { bulletinParsed = { raw_text: content, parse_error: e2.message }; }
    } else {
      bulletinParsed = { raw_text: content, parse_error: 'no JSON detected' };
    }
  }
}

let scoresData = {};
try { scoresData = $('Calcul scores (JS)1').first().json; } catch(e) {}

return [{
  json: {
    ...scoresData,
    bulletin_structure: bulletinParsed
  }
}];

